const PROCESSING_FEE = 5;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const policyBasePremium = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const mainItems = items.filter((i) => !isComponent(i));
  const mainsBase = mainItems.reduce((sum, i) => sum + itemBasePremium(i), 0);

  const byType = new Map<string, number>();
  for (const c of components) byType.set(c.type, (byType.get(c.type) ?? 0) + 1);

  let componentsBase = 0;
  for (const [type, count] of byType) {
    if (count === COMPONENT_BLOCK_SIZE) {
      componentsBase += COMPONENT_BLOCK_PREMIUM;
    } else {
      componentsBase += count * (BASE_PREMIUMS[type] ?? 0);
    }
  }
  return mainsBase + componentsBase;
};

const quotePremium = (items: Item[]): number => {
  const base = policyBasePremium(items);
  const withFirstInsurance = (base * 110) / 100;
  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
};

