toolUseResult.originalFile:
type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Customer = { yearsWithMHPCO: number };
type Scenario = { customer: Customer; steps: Step[] };
type QuoteResult = { premium: number };
type Result = QuoteResult;

const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const quotePremium = (items: Item[]): number => {
  const policyBase = items.reduce((sum, i) => sum + itemBasePremium(i), 0);
  const withFirstInsurance = (policyBase * 110) / 100;
  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): { results: Result[] } => {
  const results: Result[] = scenario.steps.map((step) => ({
    premium: quotePremium(step.items),
  }));
  return { results };
};

