import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Simplest quote cases (base premiums + processing fee) ---
  it("empty item list → premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("single plain sword, newcomer first quote → 100 base + 10 first = 110 + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single plain amulet, newcomer first quote → 60 base + 6 first = 66 + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", material: "silver", enchantment: 1, cursed: false }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single plain staff, newcomer first quote → 80 base + 8 first = 88 + 5 fee = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff", material: "wood", enchantment: 1, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single plain potion, newcomer first quote → 40 base + 4 first = 44 + 5 fee = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });
  it("single rune, newcomer first quote → 25 base + 2.5 first = 27.5 + 5 fee = 33 G (ceil)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });
  it("single moonstone, newcomer first quote → 25 base + 2.5 first = 27.5 + 5 fee = 33 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "moonstone" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });

  // --- Building block of 3 alike components ---
  it("2 runes (newcomer) → base 50 + 5 first + 5 fee = 60 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes (newcomer) → block base 60 + 6 first + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("4 runes (newcomer) → base 100 + 10 first + 5 fee = 115 G (no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("7 runes (newcomer) → base 175 + 17.5 first + 5 fee = 198 G (no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: Array.from({ length: 7 }, () => ({ type: "rune" })),
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 198 }] });
  });

  // --- Alike components clarification ---
  it("2 runes + 1 moonstone (newcomer) → base 75 + 7.5 first + 5 fee = 88 G (no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 88 }] });
  });
  it("3 runes + 3 moonstones (newcomer) → base 120 (2 blocks) + 12 first + 5 fee = 137 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" }, { type: "rune" }, { type: "rune" },
            { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
          ],
        },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 137 }] });
  });

  // --- Item-specific modifiers ---
  it("cursed sword (newcomer) → 100 base + 50 curse + 10 first + 5 fee = 165 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 165 }] });
  });
  it("sword ench 5 (newcomer) → 100 base + 30 high-ench + 10 first + 5 fee = 145 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 145 }] });
  });
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 → both surcharges apply");

  // --- Policy-wide modifiers ---
  it.todo("customer with exactly 2 years → loyalty discount applies (20%)");
  it.todo("customer with 0 years → no loyalty discount");
  it.todo("first quote of a customer → 10% first insurance surcharge applies");
  it.todo("second quote of a customer → 15% follow-up contract discount applies");

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword + plain amulet → policy base 160 G, +50 G curse, +5 fee = 215 G");

  // --- Rounding in MHPCO's favor (premium rounds up) ---
  it.todo("premium that yields 197.5 G → 198 G (rounded up)");

  // --- Integration examples from spec ---
  it.todo("newcomer with cursed sword (steel, ench 3), 0 yrs → premium 165 G");
  it.todo("long-standing customer's 2nd contract, cursed sword ench 7 → premium 160 G");

  // --- Claim processing: basic deductible and reimbursement ---
  it.todo("regular sword (steel ench 3), damage 500 G → payout 400 G (500 − 100 deductible)");
  it.todo("rune damage 200 G → payout 100 G (no special clause, − deductible)");

  // --- Dragon material clause ---
  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (full − deductible)");

  // --- High-enchantment clause (>= 8) ---
  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% − deductible)");
  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (50% wins, − deductible)");
  it.todo("dragon-material sword, ench exactly 8, damage 1000 G → payout 400 G (50% applies, − deductible)");

  // --- Deductible per damage event (per damaged item) ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible per item)");

  // --- Multiple items of same type ---
  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G; both damaged → two deductibles");
  it.todo("claim with more sword damages than swords insured → CLI exits non-zero");

  // --- Cap exhaustion ---
  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
  it.todo("sword + 3 runes block → insurance sum 1750 G (block discount affects premium only)");
  it.todo("two successive 1500 G claims on sword (cap 2000): payouts 1400, 600; remainingCap 600, 0");

  // --- Rounding of payout (rounds down — MHPCO's favor) ---
  it.todo("payout that yields 350.5 G → 350 G (rounded down)");

  // --- Edge cases ---
  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr");
  it.todo("claim references damage item not in policy → CLI exits non-zero, error to stderr");
  it.todo("claim damage with negative amount → CLI exits non-zero, error to stderr");
});

